1	type Cell = [number, number]; // [x, y]
2	
3	function countLiveNeighbors(cells: Cell[], [x, y]: Cell): number {
4	  return cells.filter(
5	    ([nx, ny]) =>
6	      !(nx === x && ny === y) &&
7	      Math.abs(nx - x) <= 1 &&
8	      Math.abs(ny - y) <= 1,
9	  ).length;
10	}
11	
12	function survives(liveNeighbors: number): boolean {
13	  return liveNeighbors === 2 || liveNeighbors === 3;
14	}
15	
16	function isBornByReproduction(liveNeighbors: number): boolean {
17	  return liveNeighbors === 3;
18	}
19	
20	function isAlive(cells: Cell[], [x, y]: Cell): boolean {
21	  return cells.some(([cx, cy]) => cx === x && cy === y);
22	}
23	
24	const OFFSETS = [-1, 0, 1];
25	
26	function cellKey([x, y]: Cell): string {
27	  return `${x},${y}`;
28	}
29	
30	function candidateCells(cells: Cell[]): Cell[] {
31	  const seen = new Map<string, Cell>();
32	  for (const [x, y] of cells) {
33	    for (const dx of OFFSETS) {
34	      for (const dy of OFFSETS) {
35	        const candidate: Cell = [x + dx, y + dy];
36	        seen.set(cellKey(candidate), candidate);
37	      }
38	    }
39	  }
40	  return [...seen.values()];
41	}
42	
43	/**
44	 * Computes the next generation of live cells from the current live cells,
45	 * applying Conway's rules.
46	 */
47	export function nextGeneration(cells: Cell[]): Cell[] {
48	  return candidateCells(cells).filter((cell) => {
49	    const liveNeighbors = countLiveNeighbors(cells, cell);
50	    return isAlive(cells, cell)
51	      ? survives(liveNeighbors)
52	      : isBornByReproduction(liveNeighbors);
53	  });
54	}
